import{_ as a}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{c as i,o as e,X as t}from"./chunks/vendor-vueuse.XPft87tp.js";const y=JSON.parse('{"title":"怎么区分数组和对象？typeof 不顶用","description":"","frontmatter":{},"headers":[],"relativePath":"basics/array-vs-object.md","filePath":"basics/array-vs-object.md","lastUpdated":1784884957000}'),n={name:"basics/array-vs-object.md"};function r(l,s,p,h,o,c){return e(),i("div",null,s[0]||(s[0]=[t('<h1 id="怎么区分数组和对象-typeof-不顶用" tabindex="-1">怎么区分数组和对象？<code>typeof</code> 不顶用 <a class="header-anchor" href="#怎么区分数组和对象-typeof-不顶用" aria-label="Permalink to &quot;怎么区分数组和对象？`typeof` 不顶用&quot;">​</a></h1><p>面试问&quot;怎么判断一个变量是数组&quot;，有人上来就说 <code>typeof</code>——不行。<code>typeof []</code> 的结果是 <code>&quot;object&quot;</code>，和 <code>typeof {}</code> 一模一样。</p><h2 id="方法-1-array-isarray" tabindex="-1">方法 1：<code>Array.isArray()</code> <a class="header-anchor" href="#方法-1-array-isarray" aria-label="Permalink to &quot;方法 1：`Array.isArray()`&quot;">​</a></h2><div class="language-javascript vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes dracula vitesse-black vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#F8F8F2;--shiki-dark:#BD976A;">Array</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">.</span><span style="--shiki-light:#50FA7B;--shiki-dark:#80A665;">isArray</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">([]);</span><span style="--shiki-light:#6272A4;--shiki-dark:#758575DD;">   // true</span></span>\n<span class="line"><span style="--shiki-light:#F8F8F2;--shiki-dark:#BD976A;">Array</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">.</span><span style="--shiki-light:#50FA7B;--shiki-dark:#80A665;">isArray</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">({});</span><span style="--shiki-light:#6272A4;--shiki-dark:#758575DD;">   // false</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>ES5 引入的官方方案，最推荐。不存在跨 iframe 的问题，语义明确。</p><h2 id="方法-2-instanceof" tabindex="-1">方法 2：<code>instanceof</code> <a class="header-anchor" href="#方法-2-instanceof" aria-label="Permalink to &quot;方法 2：`instanceof`&quot;">​</a></h2><div class="language-javascript vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes dracula vitesse-black vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">[]</span><span style="--shiki-light:#FF79C6;--shiki-dark:#CB7676;"> instanceof</span><span style="--shiki-light:#8BE9FD;--shiki-light-font-style:italic;--shiki-dark:#5DA994;--shiki-dark-font-style:inherit;"> Array</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">;</span><span style="--shiki-light:#6272A4;--shiki-dark:#758575DD;">   // true</span></span>\n<span class="line"><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">{}</span><span style="--shiki-light:#FF79C6;--shiki-dark:#CB7676;"> instanceof</span><span style="--shiki-light:#8BE9FD;--shiki-light-font-style:italic;--shiki-dark:#5DA994;--shiki-dark-font-style:inherit;"> Array</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">;</span><span style="--shiki-light:#6272A4;--shiki-dark:#758575DD;">   // false</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>大部分场景没问题，但有坑：如果数组来自另一个 iframe 或 window，它的 <code>Array</code> 构造函数和当前环境不是同一个，<code>instanceof</code> 会返回 <code>false</code>。这就是为什么 <code>Array.isArray()</code> 更靠谱。</p><h2 id="方法-3-object-prototype-tostring-call" tabindex="-1">方法 3：<code>Object.prototype.toString.call()</code> <a class="header-anchor" href="#方法-3-object-prototype-tostring-call" aria-label="Permalink to &quot;方法 3：`Object.prototype.toString.call()`&quot;">​</a></h2><div class="language-javascript vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes dracula vitesse-black vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8BE9FD;--shiki-light-font-style:italic;--shiki-dark:#B8A965;--shiki-dark-font-style:inherit;">Object</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">.</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#B8A965;">prototype</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">.</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#BD976A;">toString</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">.</span><span style="--shiki-light:#50FA7B;--shiki-dark:#80A665;">call</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">([]);</span><span style="--shiki-light:#6272A4;--shiki-dark:#758575DD;">   // &quot;[object Array]&quot;</span></span>\n<span class="line"><span style="--shiki-light:#8BE9FD;--shiki-light-font-style:italic;--shiki-dark:#B8A965;--shiki-dark-font-style:inherit;">Object</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">.</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#B8A965;">prototype</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">.</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#BD976A;">toString</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">.</span><span style="--shiki-light:#50FA7B;--shiki-dark:#80A665;">call</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">({});</span><span style="--shiki-light:#6272A4;--shiki-dark:#758575DD;">   // &quot;[object Object]&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这个方法能精确区分各种内置类型，包括 <code>Date</code>、<code>RegExp</code> 等。它是通过读取内部 <code>[[Class]]</code> 属性来判断的，不受跨环境影响。兼容性也最好，IE 都支持。</p><h2 id="方法-4-检查-constructor" tabindex="-1">方法 4：检查 <code>constructor</code> <a class="header-anchor" href="#方法-4-检查-constructor" aria-label="Permalink to &quot;方法 4：检查 `constructor`&quot;">​</a></h2><div class="language-javascript vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes dracula vitesse-black vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">[].</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#B8A965;">constructor</span><span style="--shiki-light:#FF79C6;--shiki-dark:#CB7676;"> ===</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#BD976A;"> Array</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">;</span><span style="--shiki-light:#6272A4;--shiki-dark:#758575DD;">   // true</span></span>\n<span class="line"><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">{}.</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#B8A965;">constructor</span><span style="--shiki-light:#FF79C6;--shiki-dark:#CB7676;"> ===</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#BD976A;"> Object</span><span style="--shiki-light:#F8F8F2;--shiki-dark:#444444;">;</span><span style="--shiki-light:#6272A4;--shiki-dark:#758575DD;">  // true</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>不推荐。<code>constructor</code> 可以被篡改，而且同样有跨 iframe 的问题。</p><h2 id="到底用哪个" tabindex="-1">到底用哪个 <a class="header-anchor" href="#到底用哪个" aria-label="Permalink to &quot;到底用哪个&quot;">​</a></h2><p>日常开发中 <code>Array.isArray()</code> 是标准答案。如果你在写工具库需要兼容极端情况，<code>Object.prototype.toString.call()</code> 是最稳的兜底方案。<code>typeof</code> 只适用于区分基本类型，引用类型一律返回 <code>&quot;object&quot;</code>（<code>typeof null</code> 也是 <code>&quot;object&quot;</code>，这是个著名的历史 bug）。</p>',16)]))}const F=a(n,[["render",r]]);export{y as __pageData,F as default};
